css:
/* 1-bit Desktop Dither Pattern */
body {
  background: url('data:image/svg+xml;base64,') repeat !important;
}

/* Window styling (Cards & Modals) */
.bg-theme-surface, .card, .modal-content {
  background: #fff !important;
  border: 2px solid #000 !important;
  box-shadow: 2px 2px 0px 0px #000 !important;
  border-radius: 4px !important;
}

/* Classic Window Title Bars with Stripes */
h2.flex.items-center, .border-b > h3.font-bold, .bg-theme-surface > .border-b {
  position: relative;
  background: #fff;
  border-bottom: 2px solid #000;
  padding-top: 8px;
  padding-bottom: 8px;
  display: flex;
  justify-content: center;
  text-align: center;
}
h2.flex.items-center::before, .border-b > h3.font-bold::before, .bg-theme-surface > .border-b::before {
  content: ''; position: absolute; inset: 0;
  background: repeating-linear-gradient(to bottom, #000, #000 1px, transparent 1px, transparent 2px);
  opacity: 0.3; z-index: 0;
}
/* Clear stripes behind the title text */
h2.flex.items-center > *, .border-b > h3.font-bold > *, .bg-theme-surface > .border-b > h3 {
  background: #fff;
  padding: 0 10px;
  position: relative;
  z-index: 1;
  font-weight: 700;
}

/* Classic Buttons (Double Borders, Inverted on Active) */
.btn-primary, .btn-secondary {
  background: #fff !important;
  color: #000 !important;
  border: 2px solid #000 !important;
  border-radius: 16px !important;
  box-shadow: none !important;
  position: relative;
  overflow: hidden;
  font-weight: 700;
  letter-spacing: 0.05em;
}
.btn-primary::after, .btn-secondary::after {
  content: ''; position: absolute; inset: 2px;
  border: 1px solid #000; border-radius: 12px; pointer-events: none;
}
.btn-primary:active, .btn-secondary:active, .btn-primary:hover, .btn-secondary:hover {
  background: #000 !important;
  color: #fff !important;
}
.btn-primary:active::after, .btn-secondary:active::after, .btn-primary:hover::after, .btn-secondary:hover::after {
  border-color: #fff;
}

/* Kill Anti-aliasing for true pixel look */
* {
  -webkit-font-smoothing: none !important;
  font-smooth: never !important;
}
::selection { background: #000 !important; color: #fff !important; }

/* Hover Inverts Table Rows */
tr:hover td { background: #000 !important; color: #fff !important; }
tr:hover td a, tr:hover td span, tr:hover td svg { color: #fff !important; }

/* Scrollbar Dither */
::-webkit-scrollbar-track {
  background: url('data:image/svg+xml;base64,') !important;
  border-left: 2px solid #000;
}
::-webkit-scrollbar-thumb {
  background: #fff !important;
  border: 2px solid #000;
}
